// src/processor.ts
var processEvent = async (event, log) => {
  switch (event.type) {
    case "SYNC_MAILBOXES":
      return syncMailboxes(event, log);
    case "SYNC_MESSAGES":
      return syncMessages(event, log);
    case "FETCH_BODY":
      return fetchBody(event, log);
    case "UPDATE_FLAGS":
      return updateFlags(event, log);
    default:
      throw new Error(`Unknown event type: ${event.type}`);
  }
};

